const body = $input.first().json.body;

// Mensagem do OPERADOR HUMANO (fromMe=true) — marca silêncio de 1 hora
if (
  body.event === 'message' &&
  body.payload.fromMe === true &&
  body.payload.body &&
  body.payload.body.trim() !== '' &&
  body.payload._data?.type !== 'e2e_notification'
) {
  return [{ json: { body, isHumanTakeover: true } }];
}

// Mensagem real do LEAD
const isRealMessage = (
  body.event === 'message' &&
  !body.payload.fromMe &&
  body.payload.body &&
  body.payload.body.trim() !== '' &&
  body.payload._data?.type !== 'e2e_notification'
);

if (isRealMessage) {
  const msgText = body.payload.body;
  const lowerMsg = msgText.toLowerCase();

  // 1. FILTRO DE NÃO-HUMANOS (ALEX 9.1) (Sistemas e Robôs)
  const isSystemMsg = ['cod. do pedido', 'pagamento confirmado', 'assistente virtual', 'seu código', 'digite a opção', 'saldo atual', 'atendimento automatizado', 'protocolo de atendimento', 'comprovante'].some(w => lowerMsg.includes(w));
  if (isSystemMsg) {
    return []; // Descarta silenciosamente (evita loop com outros bots)
  }

  // 2. DETECTOR DE EMOJIS
  // Remove todos os emojis. Se não sobrar texto (ou só espaços), é apenas emoji.
  const textoSemEmoji = msgText.replace(/[\p{Emoji_Presentation}\p{Emoji}\uFE0F\u200D]/gu, '').trim();

  if (textoSemEmoji === '') {
    // É apenas emoji.
    return [];
  }

  return [{ json: { ...body, isHumanTakeover: false } }];
}

return []; // Descarta ruído

